import{_ as t,o as e,c as o,ag as i}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"About","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1774874713000}'),s={name:"about.md"};function r(n,a,l,c,u,h){return e(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h1><div class="profile-header"><div class="profile-info"><h1>Qi Meng</h1><div class="title">Condensed Matter Physics | Ph.D. Candidate</div><div class="profile-links"><a href="mailto:qimeng0103@gmail.com">Email</a><a href="https://github.com/qimeng0103" target="_blank">GitHub</a><a href="https://scholar.google.com" target="_blank">Google Scholar</a><a href="https://orcid.org" target="_blank">ORCID</a></div></div></div><h2 id="research-interests" tabindex="-1">Research Interests <a class="header-anchor" href="#research-interests" aria-label="Permalink to &quot;Research Interests&quot;">​</a></h2><p>My research focuses on theoretical and computational condensed matter physics, with particular emphasis on:</p><div class="research-areas"><h4>Topological Phases of Matter</h4><p>Theoretical studies of topological insulators, topological superconductors, and Weyl semimetals</p><h4>Quantum Transport</h4><p>Electronic transport properties in mesoscopic systems using non-equilibrium Green&#39;s functions and scattering matrix approaches</p><h4>Strongly Correlated Systems</h4><p>Numerical simulations of quantum many-body systems, including DMRG and quantum Monte Carlo methods</p><h4>Quantum Computing</h4><p>Theoretical studies of quantum algorithms, quantum error correction, and quantum simulation</p></div><h2 id="education" tabindex="-1">Education <a class="header-anchor" href="#education" aria-label="Permalink to &quot;Education&quot;">​</a></h2><ul><li><p><strong>Ph.D. in Physics</strong> (2022–Present)<br> Research Institute, University</p></li><li><p><strong>B.S. in Physics</strong> (2018–2022)<br> University</p></li></ul><h2 id="publications" tabindex="-1">Publications <a class="header-anchor" href="#publications" aria-label="Permalink to &quot;Publications&quot;">​</a></h2><div class="publications-list"><li><div class="publication-title">Example Paper Title on Topological Physics</div><div class="publication-authors">Q. Meng, A. Author, B. Author</div><div class="publication-journal">Physical Review B 00, 000000 (2024)</div></li></div><h2 id="technical-skills" tabindex="-1">Technical Skills <a class="header-anchor" href="#technical-skills" aria-label="Permalink to &quot;Technical Skills&quot;">​</a></h2><p><strong>Programming Languages:</strong> Python, Julia, MATLAB, C/C++</p><p><strong>Computational Tools:</strong> Kwant, ITensor, Quantum ESPRESSO, COMSOL</p><p><strong>Numerical Methods:</strong> DMRG, Quantum Monte Carlo, Exact Diagonalization, Green&#39;s Functions</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><ul><li><strong>Email:</strong> <a href="mailto:qimeng0103@gmail.com" target="_blank" rel="noreferrer">qimeng0103@gmail.com</a></li><li><strong>GitHub:</strong> <a href="https://github.com/qimeng0103" target="_blank" rel="noreferrer">@qimeng0103</a></li></ul><hr><blockquote><p><em>&quot;The first principle is that you must not fool yourself — and you are the easiest person to fool.&quot;</em></p><p>— Richard Feynman</p></blockquote>',17)])])}const m=t(s,[["render",r]]);export{p as __pageData,m as default};
